import React from "react";
import { Card, CardContent, Typography } from "@mui/material";
import { DataGrid } from "@mui/x-data-grid";

const rows = [
  { id: 1, doctor: "Dr. Sharma", type: "Clinic Visit", notes: "Discussed diabetes drug" },
  { id: 2, doctor: "Dr. Patel", type: "Video Call", notes: "Requested brochure" }
];

const columns = [
  { field: "doctor", headerName: "Doctor", width: 200 },
  { field: "type", headerName: "Interaction Type", width: 200 },
  { field: "notes", headerName: "Notes", width: 400 }
];

export default function InteractionHistory() {
  return (
    <Card sx={{ borderRadius: 4, boxShadow: 6 }}>
      <CardContent>

        <Typography variant="h5" gutterBottom>
          Interaction History
        </Typography>

        <div style={{ height: 300 }}>
          <DataGrid rows={rows} columns={columns} />
        </div>

      </CardContent>
    </Card>
  );
}
